// Normalize form item and detect short Maps link (so we can branch: short = HTTP Request, else = ParseAndValidate).
const item = $input.first().json;
const get = (name) => {
  const v = item[name];
  if (v !== undefined && v !== null) return v;
  const key = Object.keys(item).find(k => k.trim() === name);
  return key !== undefined ? item[key] : undefined;
};
const captureLocation = (get('Capture Location') ?? '').toString().trim();
const isShortLink = /^(https?:\/\/)?(www\.)?(maps\.app\.goo\.gl|goo\.gl\/maps)\/\S+/i.test(captureLocation);
return [{ json: { ...item, captureLocation, isShortLink } }];

// Parse coords from HTTP response body (Google Maps page HTML). Form data from Normalize and Check.
const form = $('Normalize and Check').first().json;
const get = (name) => { const v = form[name]; if (v !== undefined && v !== null) return v; const key = Object.keys(form).find(k => k.trim() === name); return key !== undefined ? form[key] : undefined; };
const bookingUid = get('Booking ID');
const cleanerId = get('Cleaner ID');
const confirmArrival = (get('Confirm Arrival') ?? '').toString().trim();
if (!confirmArrival || confirmArrival.toLowerCase() !== 'yes') throw new Error('Arrival not confirmed');

const resp = $input.first().json;
const raw = (resp.data != null ? resp.data : resp.body != null ? resp.body : typeof resp === 'string' ? resp : JSON.stringify(resp));
const str = typeof raw === 'string' ? raw : String(raw);
// Match q=lat%2Clng or lat,lng or 3dLat...4dLng in HTML
let m = str.match(/q=(-?\d+\.\d+)%2C(-?\d+\.\d+)/);
if (!m) m = str.match(/(-?\d+\.\d+),(-?\d+\.\d+)/);
if (!m) m = str.match(/3d(-?\d+\.\d+)[^4]*4d(-?\d+\.\d+)/);
if (!m) throw new Error('Could not find coordinates in short link response.');
const gpsLat = m[1];
const gpsLng = m[2];

return [{
  json: {
    bookingUid,
    cleanerId,
    gpsLat,
    gpsLng,
    submissionTimestamp: new Date().toISOString(),
    processingStatus: 'PENDING',
    resultMessage: '',
    processedAt: ''
  }
}];

// ParseAndValidate: full URL, lat,lng, or DMS. Use captureLocation when present (from Normalize and Check).
const item = $('Normalize and Check').first().json;
const get = (name) => {
  const v = item[name];
  if (v !== undefined && v !== null) return v;
  const key = Object.keys(item).find(k => k.trim() === name);
  return key !== undefined ? item[key] : undefined;
};
const bookingUid = get('Booking ID');
const cleanerId = get('Cleaner ID');
const confirmArrival = (get('Confirm Arrival') ?? '').toString().trim();
const mapsLink = (item.captureLocation != null ? item.captureLocation : get('Capture Location') ?? '').toString().trim();
if (!confirmArrival || confirmArrival.toLowerCase() !== 'yes') throw new Error('Arrival not confirmed');
if (!mapsLink) throw new Error('Location link missing');

function parseLatLngFromString(str) {
  const latLngRegex = /(-?\d+\.\d+),(-?\d+\.\d+)/;
  const m = str.match(latLngRegex);
  if (m) return { lat: m[1], lng: m[2] };
  const dmsRegex = /(\d+)[°º]\s*(\d+)['′]\s*([\d.]+)["″]?\s*([NS])\s*(\d+)[°º]\s*(\d+)['′]\s*([\d.]+)["″]?\s*([EW])/i;
  const dms = str.match(dmsRegex);
  if (!dms) return null;
  const latSign = dms[4].toUpperCase() === 'S' ? -1 : 1;
  const lngSign = dms[8].toUpperCase() === 'W' ? -1 : 1;
  const lat = latSign * (parseInt(dms[1],10) + parseInt(dms[2],10)/60 + parseFloat(dms[3])/3600);
  const lng = lngSign * (parseInt(dms[5],10) + parseInt(dms[6],10)/60 + parseFloat(dms[7])/3600);
  return { lat: String(lat), lng: String(lng) };
}
const parsed = parseLatLngFromString(mapsLink);
if (!parsed) throw new Error('Invalid Google Maps link format: could not find coordinates (use a link that opens to a pin, or paste lat,lng or DMS).');
return [{ json: { bookingUid, cleanerId, gpsLat: parsed.lat, gpsLng: parsed.lng, submissionTimestamp: new Date().toISOString(), processingStatus: 'PENDING', resultMessage: '', processedAt: '' } }];

const existing = $input.all();
let parsed;
let parsedFromShortLink;
let parsedFromDirect;
try { parsedFromShortLink = $('Parse Short Link Response').first().json; } catch (_) {}
try { parsedFromDirect = $('ParseAndValidate').first().json; } catch (_) {}

// Pick the one whose submissionTimestamp is more recent — that is
// the one that actually just ran for this branch.
if (parsedFromShortLink && parsedFromDirect) {
  const tsA = new Date(parsedFromShortLink.submissionTimestamp || 0).getTime();
  const tsB = new Date(parsedFromDirect.submissionTimestamp || 0).getTime();
  parsed = tsA >= tsB ? parsedFromShortLink : parsedFromDirect;
} else {
  parsed = parsedFromShortLink || parsedFromDirect;
}
if (!parsed) throw new Error('Missing parsed submission');

const hasApproved = existing.some(i => 
  (i.json?.processingStatus ?? '').toString().trim() === 'APPROVED');
if (hasApproved) return [{ json: { skipInsert: true } }];
return [{ json: { ...parsed, skipInsert: false } }];
